        if not data:
            return jsonify({'error': 'No JSON data provided'}), 400

        ciphertext = data.get('ciphertext')
        private_key = data.get('private_key')
        key_id = data.get('key_id')

        if not ciphertext:
            return jsonify({'error': 'Ciphertext is required'}), 400

        # Get private key
        if key_id:
            if key_id not in key_storage:
                return jsonify({'error': 'Key ID not found'}), 404
            private_key = key_storage[key_id]['keys']['private_key']
        elif not private_key:
            return jsonify({'error': 'Either private_key or key_id is required'}), 400

        plaintext = PQCryptoService.kyber_decrypt(ciphertext, private_key)

        return jsonify({
            'plaintext': plaintext,
            'message': 'Message decrypted successfully'
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/keys', methods=['GET'])
def list_keys():
    """List all stored keys (metadata only)"""
    keys_info = {}
    for key_id, key_data in key_storage.items():
        keys_info[key_id] = {
            'algorithm': key_data['algorithm'],
            'created_at': key_data['created_at']
        }

    return jsonify({
        'keys': keys_info,
        'total': len(keys_info)
