            shared_secret = ephemeral_private.exchange(recipient_public_key)

            # Derive encryption key from shared secret
            hkdf = HKDF(
                algorithm=hashes.SHA256(),
                length=32,
                salt=None,
                info=b'pqc_encryption'
            )
