            ciphertext_b64 = encrypted_data.get("ciphertext")
            nonce_b64 = encrypted_data.get("nonce")
            ephemeral_public_key_b64 = encrypted_data.get("ephemeral_public_key")

            ciphertext = base64.b64decode(ciphertext_b64)
            nonce = base64.b64decode(nonce_b64)
            ephemeral_public_key_pem = base64.b64decode(ephemeral_public_key_b64)

            # Load private key
            private_key_pem = base64.b64decode(private_key_b64)
            private_key = serialization.load_pem_private_key(
                private_key_pem,
                password=None
            )

            # Load ephemeral public key
            ephemeral_public_key = serialization.load_pem_public_key(
                ephemeral_public_key_pem
            )

            # Derive shared secret
            shared_secret = private_key.exchange(ephemeral_public_key)

            # Derive decryption key
            hkdf = HKDF(
                algorithm=hashes.SHA256(),
                length=32,
                salt=None,
                info=b'pqc_encryption'
            )
            decryption_key = hkdf.derive(shared_secret)

            # Decrypt message
            cipher = ChaCha20Poly1305(decryption_key)
            plaintext = cipher.decrypt(nonce, ciphertext, None)

            return plaintext.decode('utf-8')
        except Exception as e:
            return {"error": str(e)}

